from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of Triples about food into a single fluent sentence.
    """
    if not triples:
        return ""

    # Helper to turn a single triple into a phrase
    def predicate_to_phrase(p: str, o: str) -> str:
        # Mapping predicates to phrase fragments without repeating the subject
        if p == "country":
            return f"is from {o}"
        if p == "ingredient":
            return f"contains {o}"
        if p == "region":
            return f"originates from {o}"
        if p == "division":
            return f"belongs to the division {o}"
        if p == "family":
            return f"is in the family {o}"
        if p == "order":
            return f"is classified under the order {o}"
        if p == "class":
            return f"belongs to the class {o}"
        if p == "genus":
            return f"belongs to the genus {o}"
        if p == "course":
            return f"is served as a {o}"
        if p == "capital":
            return f"has capital {o}"
        if p == "leader":
            return f"has leader {o}"
        if p == "leaderTitle":
            return f"has leader titled {o}"
        if p == "alternativeName":
            return f"is also known as {o}"
        if p == "creator":
            return f"was created by {o}"
        if p == "creatorOfDish":
            return f"was created by {o}"
        if p == "mainIngredient":
            return f"has main ingredients {o}"
        if p == "dishVariation":
            return f"can vary with {o}"
        if p == "servingTemperature" or p == "served":
            return f"is served {o}"
        if p == "year":
            return f"was introduced in {o}"
        if p == "carbohydrate":
            return f"contains {o} of carbohydrates"
        if p == "fat":
            return f"contains {o} of fat"
        if p == "protein":
            return f"contains {o} of protein"
        if p == "servingSize":
            return f"has serving size {o}"
        if p == "related":
            return f"is related to {o}"
        if p == "similarDish":
            return f"is similar to {o}"
        if p == "isPartOf":
            return f"is part of {o}"
        if p == "currency":
            return f"uses currency {o}"
        if p == "demonym":
            return f"has demonym {o}"
        if p == "language":
            return f"speaks {o}"
        if p == "officialLanguage":
            return f"has official language {o}"
        if p == "ethnicGroup":
            return f"has ethnic group {o}"
        if p == "foundationPlace":
            return f"was founded in {o}"
        # Default generic phrasing
        return f"{p} {o}"

    # Build more fluent sentence by grouping predicates per subject
    from collections import defaultdict

    subject_map = defaultdict(list)
    for t in triples:
        subject_map[t.subject].append(t)

    subject_clauses = []
    for subj, tlist in subject_map.items():
        # Convert each predicate/object pair to a short phrase
        parts = []
        for t in tlist:
            # reuse the existing helper but strip leading subject name if present
            phrase = triple_to_phrase(t)
            # Remove redundant subject at start for smoother clause
            if phrase.lower().startswith(subj.lower() + " "):
                phrase = phrase[len(subj)+1:]
            parts.append(phrase.rstrip('.'))
        # Join parts for this subject
        if len(parts) == 1:
            clause = f"{subj} {parts[0]}"
        elif len(parts) == 2:
            clause = f"{subj} {parts[0]} and {parts[1]}"
        else:
            clause = f"{subj} " + ", ".join(parts[:-1]) + ", and " + parts[-1]
        subject_clauses.append(clause)

    # Combine subject clauses into final sentence
    if len(subject_clauses) == 1:
        sentence = subject_clauses[0]
    else:
        sentence = ", ".join(subject_clauses[:-1]) + ", and " + subject_clauses[-1]

    # Ensure final punctuation
    if not sentence.endswith('.'):
        sentence += '.'
    return sentence

# EVOLVE-BLOCK-END

